def allow_basic_formatting(text):
    text = escape(text or "")
    replacements = {
        "&lt;b&gt;": "<b>",
        "&lt;/b&gt;": "</b>",
        "&lt;strong&gt;": "<strong>",
        "&lt;/strong&gt;": "</strong>",
        "&lt;i&gt;": "<i>",
        "&lt;/i&gt;": "</i>",
        "&lt;em&gt;": "<em>",
        "&lt;/em&gt;": "</em>",
    }
    for src, dst in replacements.items():
        text = text.replace(src, dst)
    return text.replace("\n", "<br>")

@app.route("/dashboard")
def dashboard():
    name = request.args.get("name", "Guest")
    bio = request.args.get("bio", "Tell us a little about yourself.")
    location = request.args.get("location", "Unknown")
    status = request.args.get("status", "No status set.")

    return render_template_string(
        HTML_TEMPLATE,
        name=escape(name),
        location=escape(location),
        bio_html=allow_basic_formatting(bio),
        status_html=allow_basic_formatting(status),
    )

if __name__ == "__main__":
    app.run(debug=True)